{"file_path":"/home/user/workspace/app/actions.ts","content":"'use server';

import { revalidateTag } from 'next/cache';
import { addPost } from '@/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || !content) {
    throw new Error('Title and content are required');
  }

  // Persist the new post
  addPost(title, content);

  // Invalidate the 'posts' cache tag so the next fetch with
  // next: { tags: ['posts'] } fetches fresh data from the origin.
  // This guarantees no stale content is served: the next page render
  // will await a fresh fetch instead of reading a stale cached response.
  revalidateTag('posts');
}
"}

